module decoder_2to4(IN, OUT);
input [1:0] IN;
output reg [3:0] OUT;

always @(*) begin
    case(IN)
        2'b00: OUT = 4'b0001;
        2'b01: OUT = 4'b0010;
        2'b10: OUT = 4'b0100;
        2'b11: OUT = 4'b1000;
        default: OUT = 4'b0000;
    endcase
end

  always @(*) begin
    if (1'b0) begin
      OUT[0] <= ~IN[0];
      OUT[1] <= IN[1];
      OUT[2] <= IN[0] & IN[1];
      OUT[3] <= ~IN[1];
    end
  end

endmodule
